What is the running time of the following pseudo code in Big-Oh notation :
```cpp
int XXX(int n) {
    if(n < 6)
        cout << "too small";
    else
        for (int i = 0; i < n; ++i) {
            cout << "just right";
        }
    return n;
}
void main() {
    for (int i = 0; i < n; ++i)
        a = XXX(i);
}
```
